#!/usr/bin/env python3
# Fix B+A+C - calendar EDIT/CANCEL primitives (in-place, never duplicate) + active-event
# tracking & auto-fill (mirrors the binder world's currentBinderId discipline). "Move it"
# now updates the row in hand; no orphan, no re-search. Read-ground-truth-before-edit.
# dream-os = JS; gate node --check. Anchored, idempotent.
import base64, sys, os
def d(s): return base64.b64decode(s).decode("utf-8")
EDITS = [
    ("src/agent/kriyaCalendar.js", "add edit+cancel tool defs", "ICAgIH0sIHJlcXVpcmVkOiBbJ3RpdGxlJywgJ2RhdGUnLCAna2luZCddIH0gfSwKICB7IG5hbWU6ICdrcml5YV9jYWxlbmRhcl9jaGVjaycs", ""),
    ("src/agent/kriyaCalendar.js", "add returns event_id", "ICAgIHJldHVybiB7IGRpc3BsYXk6IGAke2xhYmVsfSBbJHtkYXRhLmlkfV1gLCBtdXRhdGVkOiB0cnVlIH07", "ICAgIHJldHVybiB7IGRpc3BsYXk6IGAke2xhYmVsfSBbJHtkYXRhLmlkfV1gLCBtdXRhdGVkOiB0cnVlLCBldmVudF9pZDogZGF0YS5pZCB9Ow=="),
    ("src/agent/kriyaCalendar.js", "edit+cancel executor branches", "ICByZXR1cm4geyBkaXNwbGF5OiBgRVJST1I6IHVua25vd24gY2FsZW5kYXIgdG9vbCAke25hbWV9LmAsIGVycm9yOiB0cnVlIH07", ""),
    ("src/agent/kriyaTurn.js", "track currentEventId", "ICBsZXQgY3VycmVudEJpbmRlcklkID0gKHByaW9yICYmIHByaW9yLmN1cnJlbnRCaW5kZXJJZCkgfHwgbnVsbDs=", ""),
    ("src/agent/kriyaTurn.js", "CALENDAR_EDIT_ATOMS set", "ICBjb25zdCBBVFRSSUJVVEVfQVRPTVMgPSBuZXcgU2V0KFsKICAgICdrcml5YV9tb25leScsICdrcml5YV9kYXRlJywgJ2tyaXlhX25vdGUnLCAna3JpeWFfbm90ZV9hcHBlbmQnLAogICAgJ2tyaXlhX3Bob25lJywgJ2tyaXlhX2RvYycsICdrcml5YV9zdGFnZScsICdrcml5YV9yZWFzb25mb3JhY3Rpb25fYXBwZW5kJywKICBdKTs=", ""),
    ("src/agent/kriyaTurn.js", "auto-fill active event", "ICAgICAgaWYgKEFUVFJJQlVURV9BVE9NUy5oYXModHUubmFtZSkgJiYgKGlucHV0LmJpbmRlcl9pZCA9PSBudWxsIHx8IGlucHV0LmJpbmRlcl9pZCA9PT0gJycpICYmIGN1cnJlbnRCaW5kZXJJZCkgewogICAgICAgIGlucHV0LmJpbmRlcl9pZCA9IGN1cnJlbnRCaW5kZXJJZDsKICAgICAgfQ==", ""),
    ("src/agent/kriyaTurn.js", "set currentEventId after write", "ICAgICAgaWYgKG91dGNvbWUuYmluZGVyX2lkKSBjdXJyZW50QmluZGVySWQgPSBvdXRjb21lLmJpbmRlcl9pZDs=", "ICAgICAgaWYgKG91dGNvbWUuYmluZGVyX2lkKSBjdXJyZW50QmluZGVySWQgPSBvdXRjb21lLmJpbmRlcl9pZDsKICAgICAgaWYgKG91dGNvbWUuZXZlbnRfaWQpIGN1cnJlbnRFdmVudElkID0gb3V0Y29tZS5ldmVudF9pZDs="),
    ("src/agent/kriyaTurn.js", "carry currentEventId in session", "ICAgICAgICAgIHNlc3Npb246IHsgbWVzc2FnZXMsIHBlbmRpbmdUb29sVXNlSWQ6IGxpc3Rlbi5pZCwgY3VycmVudEJpbmRlcklkIH0s", "ICAgICAgICAgIHNlc3Npb246IHsgbWVzc2FnZXMsIHBlbmRpbmdUb29sVXNlSWQ6IGxpc3Rlbi5pZCwgY3VycmVudEJpbmRlcklkLCBjdXJyZW50RXZlbnRJZCB9LA==")
]
applied = skipped = 0
for path, label, o_b64, n_b64 in EDITS:
    if not os.path.exists(path):
        print("SKIP  [%s] %s not found." % (label, path)); skipped += 1; continue
    text = open(path, encoding="utf-8").read()
    old, new = d(o_b64), d(n_b64)
    if new in text:
        print("SKIP  [%s] already applied." % label); skipped += 1; continue
    c = text.count(old)
    if c == 1:
        open(path, "w", encoding="utf-8").write(text.replace(old, new)); applied += 1; print("OK    [%s]" % label)
    elif c == 0: print("SKIP  [%s] anchor NOT FOUND." % label); skipped += 1
    else: print("SKIP  [%s] anchor x%d." % (label, c)); skipped += 1
cal = open("src/agent/kriyaCalendar.js", encoding="utf-8").read()
kt  = open("src/agent/kriyaTurn.js", encoding="utf-8").read()
checks = [
  ("edit tool def",         "name: 'kriya_calendar_edit'" in cal),
  ("cancel tool def",       "name: 'kriya_calendar_cancel'" in cal),
  ("edit executor",         "if (name === 'kriya_calendar_edit')" in cal),
  ("cancel executor",       "if (name === 'kriya_calendar_cancel')" in cal),
  ("edit reads before write","never edit a row we haven't seen" in cal),
  ("add surfaces event_id", "mutated: true, event_id: data.id" in cal),
  ("currentEventId tracked","let currentEventId = (prior && prior.currentEventId)" in kt),
  ("auto-fill active event","input.event_id = currentEventId;" in kt),
  ("set after write",       "if (outcome.event_id) currentEventId = outcome.event_id;" in kt),
  ("carried in session",    "currentBinderId, currentEventId }" in kt),
]
print(chr(10) + "-- verification --")
allok = True
for n,p in checks: print("  %s %s" % ("PASS" if p else "FAIL", n)); allok = allok and p
print(chr(10) + "(%d applied, %d skipped)" % (applied, skipped))
print("ALL CHECKS PASSED" if allok else "SOME CHECKS FAILED")
sys.exit(0 if allok else 2)
